#include <bits/stdc++.h>
using namespace std;

const int N=1010;

int n,m,s[N][N];

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v,x,y;
        scanf("%d%d%d%d",&u,&v,&x,&y);
        s[u][v]++,s[u][y+1]--,s[x+1][v]--,s[x+1][y+1]++;
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++){
            s[i][j]=s[i][j]+s[i-1][j]+s[i][j-1]-s[i-1][j-1];
            printf("%d ",s[i][j]);
        }
        puts("");
    }
    return 0;
}
